-- Supabase Schema for mperium Appliance
-- Auto-generated from data/*.json

-- 1) blog.json -> blog
create table if not exists public.blog (
  id bigint primary key,
  slug text unique not null,
  title text not null,
  excerpt text,
  category text,
  "readTime" text,
  "publishedAt" text,
  image text,
  content text
);

-- 2) locations.json -> locations
create table if not exists public.locations (
  slug text primary key,
  name text not null,
  region text,
  description text,
  "mapEmbedUrl" text,
  "subAreas" jsonb default '[]'::jsonb
);

-- 3) brands.json -> brands
create table if not exists public.brands (
  slug text primary key,
  title text not null,
  description text,
  image text,
  premium boolean default false
);

-- 4) contact.json -> contact
create table if not exists public.contact (
  id bigint generated by default as identity primary key,
  phone text,
  "phoneHref" text,
  email text,
  location text,
  "socialMedia" jsonb default '[]'::jsonb,
  reviews jsonb default '{}'::jsonb
);

-- 5) faq.json -> faq
create table if not exists public.faq (
  id bigint generated by default as identity primary key,
  question text not null,
  answer text not null
);
create unique index if not exists faq_question_uidx on public.faq (question);

-- 6) metadata.json -> metadata
create table if not exists public.metadata (
  id bigint generated by default as identity primary key,
  title text not null,
  description text,
  keywords text
);

-- 7) service-details.json -> service_details
create table if not exists public.service_details (
  slug text primary key,
  title text not null,
  description text,
  image text
);

-- 8) services-commercial.json -> services_commercial
create table if not exists public.services_commercial (
  id bigint generated by default as identity primary key,
  title text not null,
  description text,
  href text,
  icon text
);

-- 9) services-residential.json -> services_residential
create table if not exists public.services_residential (
  id bigint generated by default as identity primary key,
  title text not null,
  description text,
  href text,
  icon text
);

-- 10) testimonials.json -> testimonials
create table if not exists public.testimonials (
  id bigint generated by default as identity primary key,
  initials text,
  name text not null,
  location text,
  text text not null,
  avatar text
);

-- 11) why.json -> why
create table if not exists public.why (
  id bigint generated by default as identity primary key,
  title text not null,
  description text not null,
  icon text not null
);

-- Backward-compat migration for existing installations where why table was jsonb-based
alter table public.why add column if not exists title text;
alter table public.why add column if not exists description text;
alter table public.why add column if not exists icon text;

-- 12) areas.json -> areas
create table if not exists public.areas (
  id bigint generated by default as identity primary key,
  city text not null,
  page_index integer not null default 0,
  area_name text not null,
  created_at timestamptz not null default now()
);
create unique index if not exists areas_city_page_name_uidx on public.areas (city, page_index, area_name);

-- Seed all values from JSON files
truncate table public.blog, public.locations, public.brands, public.contact, public.faq, public.metadata, public.service_details, public.services_commercial, public.services_residential, public.testimonials, public.why, public.areas restart identity;

insert into public.blog (id, slug, title, excerpt, category, "readTime", "publishedAt", image, content) values
  (1, 'why-refrigerator-not-cooling', 'Why Is My Refrigerator Not Cooling Properly?', 'Learn the most common causes behind warm fridge sections and what you can safely check before calling a technician.', 'Refrigerator', '4 min read', '2026-03-08', 'https://blog.keepe.com/content/images/2021/06/Image-53-01.png', 'A warm refrigerator is one of the most stressful kitchen emergencies. But before you panic and call a repair service, there are several things you can check yourself.

First, verify the thermostat settings. It sounds simple, but dials often get bumped. Next, check the condenser coils at the back or bottom of the fridge. If they are covered in dust, the refrigerator can''t cool efficiently.

"Regular maintenance is key to a long-lasting appliance."

If the coils are clean and the settings are correct, listen for the evaporator fan. If you don''t hear it running, or if it''s making a strange noise, it might be time to call a professional technician.'),
  (2, 'dryer-taking-too-long', 'Dryer Taking Too Long? 6 Fast Things to Inspect', 'From clogged vents to overloaded drums, these checks can improve drying performance and reduce energy bills.', 'Dryer', '5 min read', '2026-03-04', '/legacy/assets/rafixhero3.png', 'Waiting hours for a single load of laundry to dry is frustrating and wastes energy. A slow dryer is almost always a sign of restricted airflow.

Start by cleaning the lint screen thoroughly. Then, inspect the exterior vent hood to ensure it opens freely when the dryer is running. You should also check the flexible transition hose behind the dryer for kinks or heavy lint buildup.

"A clogged dryer vent is not just inefficient; it''s a serious fire hazard."

If the airflow is clear, the issue might be a faulty heating element or a cycling thermostat. In those cases, a certified technician can quickly diagnose and replace the broken parts.'),
  (3, 'dishwasher-not-cleaning', 'Dishwasher Not Cleaning Dishes? Start Here', 'A practical checklist for spray arms, filters, detergent use, and water temperature to fix poor cleaning results.', 'Dishwasher', '4 min read', '2026-02-27', '/legacy/assets/rafixhero3.png', 'Opening your dishwasher to find dirty, cloudy dishes defeats the purpose of having this appliance. Most cleaning issues stem from simple maintenance oversights.

The most common culprit is a clogged filter. Check the bottom of your tub and clean the filter assembly. Next, inspect the spray arms. Food particles can clog the small holes, preventing water from reaching your dishes.

"Hard water can cause mineral buildup, reducing your dishwasher''s effectiveness."

Ensure your water is hot enough (at least 120°F) and you''re using a high-quality detergent. If the problem persists, the circulation pump or an inlet valve might be failing.'),
  (4, 'washer-vibration-fix', 'How to Stop Washer Vibration and Noise', 'Simple leveling and load balancing tips that prevent excessive shaking and protect your machine from damage.', 'Washer', '3 min read', '2026-02-18', '/legacy/assets/rafixhero3.png', 'A washing machine that sounds like it''s taking off can be alarming and can damage both the machine and your floors.

The first step is checking if the machine is level. Use a bubble level and adjust the feet accordingly. Also, ensure you are not overloading the drum or washing a single heavy item without balancing the load.

"A balanced washer runs quieter and lasts significantly longer."

If the machine is level but still vibrates violently, the shock absorbers or suspension springs might be worn out. These parts degrade over time and require professional replacement to restore smooth operation.'),
  (5, 'oven-not-heating-evenly', 'Oven Not Heating Evenly? Common Causes', 'Find out when uneven cooking is caused by sensors, heating elements, or airflow and when professional repair is needed.', 'Oven', '6 min read', '2026-02-10', '/legacy/assets/rafixhero3.png', 'Uneven baking can ruin your favorite recipes. When half your cookies are burnt and the other half are raw, your oven needs attention.

If you have an electric oven, visibly inspect the bake element at the bottom. It should glow red evenly. If there are dark spots, it''s likely failing. For gas ovens, check the igniter; a weak igniter won''t open the gas valve correctly.

"Proper airflow is crucial for even heat distribution."

Oven temperature sensors can also drift over time. You can recalibrate the thermostat using an oven thermometer, but if the sensor is faulty, a replacement is the only way to ensure accurate cooking temperatures.'),
  (6, 'ice-machine-low-output', 'Ice Machine Producing Too Little Ice?', 'Check water supply, filters, condenser cleanliness, and temperature settings to restore ice production speed.', 'Ice Machine', '4 min read', '2026-02-03', '/legacy/assets/rafixhero3.png', 'A slow ice maker can put a damper on your summer parties. Ice production relies on steady water flow and freezing temperatures.

Verify that your freezer is set to 0°F (-18°C) or colder. If the freezer is too warm, ice production slows down drastically. Next, check the water filter. A clogged filter reduces water flow to the ice maker.

"Change your refrigerator water filter every 6 months for optimal ice speed."

If the temperature and filter are fine, inspect the condenser coils and ensure the water inlet valve isn''t restricted. For persistent issues, a technician can test the ice maker module itself.');

