insert into public.testimonials (initials, name, location, text, avatar) values
  ('KK', 'Kat', 'Austin', '"Very good service and completely honest recommendations with transparent fair pricing. Definitely recommend this company for your appliance repair needs."', null),
  ('LH', 'Lashawn Henderson', 'Austin', '"I was having a problem with my refrigerator cooling and Roma fixed it!!! He was on time, fast and had great customer service... I highly recommend mperium Appliance!!"', null),
  ('RR', 'Rick Roemer', 'Houston', '"Excellent work! Honest. On time. Friendly. Got my washer working again!"', null),
  ('DL', 'Daniel Luque', 'Austin', '"Repaired my dryer very quickly and effectively! Was able to come the very next day so I appreciate that and even cleaned up the laundry closet which was totally unnecessary. Highly recommend!"', null),
  ('JB', 'Jessica Buchanan', 'Austin', '"Excellent experience! He responded quickly, showed up on time, and repaired our microwave efficiently. He explained everything clearly and was very professional. I would definitely use him again."', null),
  ('KA', 'Karen Anderson', 'Houston, TX', '"Great service!  Came early and fixed stove. Explaining everything,  highly recommended!!"', null),
  ('RL', 'Robbye Lewis', 'Houston, TX', '"Roma doesn’t did an excellent job! He fixed my dryer quickly and explained everything in detail! The price was fair and let me know the cost before he started! Definitely Recommend!!"', null),
  ('VM', 'Vanessa M', 'Houston, TX', '"Roma was awesome, came by quotes a price and was able to order replacement part and fix in less than a week, also was very thorough and identified another part that also needed replacing. Would highly recommend."', null),
  ('oo', 'osas obaseki', 'Houston, TX', '"They responded to my call quickly, arrived on time and the guy for sure knew his stuff and was very professional. They ordered the broken part and just like that I was back cooking. Overall I highly recommend them"', null),
  ('MM', 'Melinda Myers', 'Houston, TX', '"The technician was very thorough and explained things and the price was reasonable. When we ordered the part didn’t take long for him to come back to install. I would recommend this company."', null),
  (null, 'Treasure Dimalanta', 'Houston, TX', '"very satisfied with the work and timing. he came in assessed the problem, ordered parts quickly, and returned to finish the job. even took the time to make sure the water came out clean and the filter was working."', '/legacy/assets/20260219154000673_691e71e2-e918-4cea-804d-9a1cd3e8c0be.png');

